module RefModule
(
    input clk,
    input we,
    input [8:0] addr,
    input [31:0] wdata,
    output reg [31:0] rdata
);

reg [31:0] unused_ram [511:0];

always @(posedge clk) begin
    if (we) begin
        unused_ram[addr] <= wdata;
    end
    rdata <= unused_ram[addr];
end

endmodule
